external_knowledge:
- "most popular" refers to the activities with the highest visit counts; 
- "daily" means the ranking is done separately for each date; 
- "activities" can be either exhibitions or events.

sql:
SELECT name, type
FROM museums
WHERE district = 'Albula';

SELECT name, type
FROM museums
ORDER BY name;

SELECT name
FROM museums
ORDER BY name ASC;

SELECT COUNT(*) AS museum_count
FROM museums
WHERE district = 'Anytown';

